package httpdriver

import (
	"context"
	"net/http"

	"github.com/openmeterio/openmeter/pkg/framework/operation"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
)

type ListFoosRequest struct{ Namespace string }
type ListFoosResponse struct{ Items []Foo }

func NewListFoosHandler(svc Service, errHandler httptransport.ErrorHandler) http.Handler {
	return httptransport.NewHandler(
		operation.Operation[ListFoosRequest, ListFoosResponse](func(ctx context.Context, req ListFoosRequest) (ListFoosResponse, error) {
			items, err := svc.ListFoos(ctx, req.Namespace)
			if err != nil { return ListFoosResponse{}, err }
			return ListFoosResponse{Items: items}, nil
		}),
		func(ctx context.Context, r *http.Request) (ListFoosRequest, error) {
			return ListFoosRequest{Namespace: r.Header.Get("OM-Namespace")}, nil
		},
		func(ctx context.Context, w http.ResponseWriter, resp ListFoosResponse) error {
			return commonhttp.JSONResponse(ctx, w, http.StatusOK, resp)
		},
		func(ctx context.Context, err error, w http.ResponseWriter) bool {
			return commonhttp.GenericErrorEncoder(ctx, err, w)
		},
		httptransport.WithErrorHandler(errHandler),
		httptransport.WithOperationName("ListFoos"),
	)
}
